const staticData = $getWorkflowStaticData('global');
const cfg = staticData.config || {};

const CITIES = cfg.cities || [
  'Savannah','Atlanta','Charlotte','Nashville','Memphis',
  'Jacksonville','Orlando','Tampa','Miami','Houston'
];
const INDUSTRIES = cfg.industries || [
  'electrician','plumber','HVAC contractor','roofer','landscaper',
  'painter','handyman','cleaning service','pest control','concrete contractor'
];
const maxMsg = cfg.max_whatsapp || 20;

const combos = [];
const used = new Set();
while (combos.length < 8 && combos.length < CITIES.length * INDUSTRIES.length) {
  const c = CITIES[Math.floor(Math.random() * CITIES.length)];
  const i = INDUSTRIES[Math.floor(Math.random() * INDUSTRIES.length)];
  const key = c + '|' + i;
  if (!used.has(key)) { used.add(key); combos.push({city:c, industry:i}); }
}

return combos.map(x => ({ json: { ...x, max_messages: maxMsg } }));

const results = [];
for (const item of $input.all()) {
  const places = item.json.places || [];
  const prevNode = $('Set Config & Target');
  const industry = prevNode.first ? prevNode.first().json.industry : (prevNode.item || {}).json.industry || '';
  const city = prevNode.first ? prevNode.first().json.city : (prevNode.item || {}).json.city || '';
  for (const p of places) {
    if (p.websiteUri) continue;
    const phone = p.nationalPhoneNumber || '';
    if (!phone) continue;
    results.push({ json: {
      business_name: p.displayName?.text || '',
      phone,
      industry,
      city,
      rating: p.rating || 0,
      reviews_count: p.userRatingCount || 0,
      place_id: p.id || '',
      address: p.formattedAddress || ''
    }});
    if (results.length >= 5) break;
  }
  if (results.length >= 5) break;
}
return results;

const staticData = $getWorkflowStaticData('global');
if (!staticData.whatsappMessaged) staticData.whatsappMessaged = {};

const out = [];
const maxMsg = 20;

for (const item of $input.all()) {
  const l = item.json;
  let digits = String(l.phone || '').replace(/[^0-9]/g, '');
  if (digits.length === 11 && digits.startsWith('1')) digits = digits.slice(1);
  if (digits.length !== 10) continue;
  if (staticData.whatsappMessaged[digits]) continue;
  if (out.length >= maxMsg) break;
  out.push({ json: { ...l, phone_digits: digits } });
}
return out;

const l = $input.first().json;
const previewUrl = 'https://teamgoldllc.de/preview?business=' +
  encodeURIComponent(l.business_name || '') +
  '&industry=' + encodeURIComponent(l.industry || '') +
  '&city=' + encodeURIComponent(l.city || '') +
  '&rating=' + (l.rating || '') +
  '&reviews=' + (l.reviews_count || '');

const mapsUrl = l.place_id
  ? 'https://maps.google.com/?cid=' + l.place_id
  : 'https://www.google.com/maps/search/' + encodeURIComponent(l.business_name || '');

const smsMessage = `Hey, this is Atakan from Team Gold! I saw you on Google and noticed you don't have a website. I built one for you: ${previewUrl}

Reply YES to get it live, or STOP to opt out.`;

return [{ json: { ...l, preview_url: previewUrl, maps_url: mapsUrl, sms_message: smsMessage } }];

const staticData = $getWorkflowStaticData('global');
const l = $('Generate Preview & Message').first().json;
const today = new Date().toISOString().slice(0,10);
const digits = l.phone_digits;

if (!staticData.smsMessaged) staticData.smsMessaged = {};
staticData.smsMessaged[digits] = { at: new Date().toISOString(), name: l.business_name };

if (!staticData.smsLeads) staticData.smsLeads = [];
staticData.smsLeads.push({
  business_name: l.business_name,
  phone: l.phone,
  phone_digits: digits,
  industry: l.industry,
  city: l.city,
  preview_url: l.preview_url,
  maps_url: l.maps_url,
  status: 'sent',
  sent_at: new Date().toISOString()
});
if (staticData.smsLeads.length > 500) staticData.smsLeads = staticData.smsLeads.slice(-500);

if (!staticData.smsDailyCosts) staticData.smsDailyCosts = {};
if (!staticData.smsDailyCosts[today]) staticData.smsDailyCosts[today] = {count:0, cost:0};
staticData.smsDailyCosts[today].count++;
staticData.smsDailyCosts[today].cost = parseFloat((staticData.smsDailyCosts[today].count * 0.004).toFixed(4));

return [{ json: { ...l, saved: true } }];

const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0,10);
const dayData = (staticData.smsDailyCosts || {})[today] || {count:0, cost:0};
const sent = $input.all();

let text = 'SMS OUTREACH ABGESCHLOSSEN\n\n';
text += 'Heute gesendet: ' + dayData.count + ' SMS\n';
text += 'Kosten heute: $' + dayData.cost.toFixed(4) + '\n\n';

if (sent.length > 0) {
  text += 'Diese Runde:\n';
  sent.forEach(s => {
    const l = s.json;
    text += '  - ' + (l.business_name||'?') + ' (' + (l.city||'') + ')\n';
  });
}

return [{ json: { report_text: text } }];
